const SPELL_DB = [
// CANTRIPS (level 0)
{name:"Acid Splash",level:0,school:"Conjuration",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"You hurl a bubble of acid. Choose one creature you can see within range, or choose two creatures you can see within range that are within 5 feet of each other. A target must succeed on a Dexterity saving throw or take 1d6 acid damage. This spell's damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6)."},
{name:"Blade Ward",level:0,school:"Abjuration",castingTime:"1 action",range:"Self",components:"V, S",duration:"1 round",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"You extend your hand and trace a sigil of warding in the air. Until the end of your next turn, you have resistance against bludgeoning, piercing, and slashing damage dealt by weapon attacks."},
{name:"Booming Blade",level:0,school:"Evocation",castingTime:"1 action",range:"Self (5-foot radius)",components:"S, M (a melee weapon worth at least 1 sp)",duration:"1 round",classes:["Sorcerer","Warlock","Wizard"],description:"You brandish the weapon used in the spell's casting and make a melee attack with it against one creature within 5 feet of you. On a hit, the target suffers the weapon attack's normal effects and then becomes sheathed in booming energy until the start of your next turn. If the target willingly moves 5 or more feet before then, the target takes 1d8 thunder damage, and the spell ends. This spell's damage increases when you reach certain levels."},
{name:"Chill Touch",level:0,school:"Necromancy",castingTime:"1 action",range:"120 feet",components:"V, S",duration:"1 round",classes:["Sorcerer","Warlock","Wizard"],description:"You create a ghostly, skeletal hand in the space of a creature within range. Make a ranged spell attack against the creature to assail it with the chill of the grave. On a hit, the target takes 1d8 necrotic damage, and it can't regain hit points until the start of your next turn. Until then, the hand clings to the target. If you hit an undead target, it also has disadvantage on attack rolls against you until the end of your next turn. This spell's damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8)."},
{name:"Control Flames",level:0,school:"Transmutation",castingTime:"1 action",range:"60 feet",components:"S",duration:"Instantaneous or 1 hour",classes:["Druid","Sorcerer","Wizard"],description:"You choose nonmagical flame that you can see within range and that fits within a 5-foot cube. You affect it in one of the following ways: You instantaneously expand the flame 5 feet in one direction, provided that wood or other fuel is present in the new location. You instantaneously extinguish the flames within the cube. You double or halve the area of bright light and dim light cast by the flame, change its color, or both. The change lasts for 1 hour. You cause simple shapes—such as the vague form of a creature, an inanimate object, or a location—to appear within the flames and animate as you like. The shapes last for 1 hour."},
{name:"Dancing Lights",level:0,school:"Evocation",castingTime:"1 action",range:"120 feet",components:"V, S, M (a bit of phosphorus or wychwood, or a glowworm)",duration:"Concentration, up to 1 minute",classes:["Bard","Sorcerer","Wizard"],description:"You create up to four torch-sized lights within range, making them appear as torches, lanterns, or glowing orbs that hover in the air for the duration. You can also combine the four lights into one glowing vaguely humanoid form of Medium size. Whichever form you choose, each light sheds dim light in a 10-foot radius. As a bonus action on your turn, you can move the lights up to 60 feet to a new spot within range."},
{name:"Druidcraft",level:0,school:"Transmutation",castingTime:"1 action",range:"30 feet",components:"V, S",duration:"Instantaneous",classes:["Druid"],description:"Whispering to the spirits of nature, you create one of the following effects within range: You create a tiny, harmless sensory effect that predicts what the weather will be at your location for the next 24 hours. You instantly make a flower blossom, a seed pod open, or a leaf bud bloom. You create an instantaneous, harmless sensory effect, such as falling leaves, a puff of wind, the sound of a small animal, or the faint odor of skunk. You light or snuff out a candle, a torch, or a small campfire."},
{name:"Eldritch Blast",level:0,school:"Evocation",castingTime:"1 action",range:"120 feet",components:"V, S",duration:"Instantaneous",classes:["Warlock"],description:"A beam of crackling energy streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 force damage. The spell creates more than one beam when you reach higher levels: two beams at 5th level, three beams at 11th level, and four beams at 17th level. You can direct the beams at the same target or at different ones. Make a separate attack roll for each beam.",damage:"1d10 force"},
{name:"Fire Bolt",level:0,school:"Evocation",castingTime:"1 action",range:"120 feet",components:"V, S",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"You hurl a mote of fire at a creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 fire damage. A flammable object hit by this spell ignites if it isn't being worn or carried. This spell's damage increases by 1d10 when you reach 5th level (2d10), 11th level (3d10), and 17th level (4d10).",damage:"1d10 fire"},
{name:"Friends",level:0,school:"Enchantment",castingTime:"1 action",range:"Self",components:"S, M (a small amount of makeup applied to the face as this spell is cast)",duration:"Concentration, up to 1 minute",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"For the duration, you have advantage on all Charisma checks directed at one creature of your choice that isn't hostile toward you. When the spell ends, the creature realizes that you used magic to influence its mood and becomes hostile toward you. A creature prone to violence might attack you. Another creature might seek retribution in other ways (at the DM's discretion), depending on the nature of your interaction with it."},
{name:"Frostbite",level:0,school:"Evocation",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Instantaneous",classes:["Druid","Sorcerer","Warlock","Wizard"],description:"You cause numbing frost to form on one creature that you can see within range. The target must make a Constitution saving throw. On a failed save, the target takes 1d6 cold damage, and it has disadvantage on the next weapon attack roll it makes before the end of its next turn. The spell's damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6)."},
{name:"Guidance",level:0,school:"Divination",castingTime:"1 action",range:"Touch",components:"V, S",duration:"Concentration, up to 1 minute",classes:["Cleric","Druid"],description:"You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one ability check of its choice. It can roll the die before or after making the ability check. The spell then ends."},
{name:"Infestation",level:0,school:"Conjuration",castingTime:"1 action",range:"30 feet",components:"V, S, M (a living flea)",duration:"Instantaneous",classes:["Druid","Sorcerer","Warlock","Wizard"],description:"You cause a cloud of mites, fleas, and other parasites to appear momentarily on one creature you can see within range. The target must succeed on a Constitution saving throw, or it takes 1d6 poison damage and moves 5 feet in a random direction if it can move and its speed is at least 5 feet. Roll a d4 for the direction: 1, north; 2, south; 3, east; or 4, west. This movement doesn't provoke opportunity attacks, and if the direction rolled is blocked, the target doesn't move."},
{name:"Light",level:0,school:"Evocation",castingTime:"1 action",range:"Touch",components:"V, M (a firefly or phosphorescent moss)",duration:"1 hour",classes:["Bard","Cleric","Sorcerer","Wizard"],description:"You touch one object that is no larger than 10 feet in any dimension. Until the spell ends, the object sheds bright light in a 20-foot radius and dim light for an additional 20 feet. The light can be colored as you like. Completely covering the object with something opaque blocks the light. The spell ends if you cast it again or dismiss it as an action."},
{name:"Mage Hand",level:0,school:"Conjuration",castingTime:"1 action",range:"30 feet",components:"V, S",duration:"1 minute",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration or until you dismiss it as an action. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again. You can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial. You can move the hand up to 30 feet each time you use it."},
{name:"Mending",level:0,school:"Transmutation",castingTime:"1 minute",range:"Touch",components:"V, S, M (two lodestones)",duration:"Instantaneous",classes:["Bard","Cleric","Druid","Sorcerer","Wizard"],description:"This spell repairs a single break or tear in an object you touch, such as a broken chain link, two halves of a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no larger than 1 foot in any dimension, you mend it, leaving no trace of the former damage. This spell can physically repair a magic item or construct, but the spell can't restore magic to such an object."},
{name:"Message",level:0,school:"Transmutation",castingTime:"1 action",range:"120 feet",components:"V, S, M (a short piece of copper wire)",duration:"1 round",classes:["Bard","Sorcerer","Wizard"],description:"You point your finger toward a creature within range and whisper a message. The target (and only the target) hears the message and can reply in a whisper that only you can hear. You can cast this spell through solid objects if you are familiar with the target and know it is beyond the barrier. Magical silence, 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood blocks the spell. The spell doesn't have to follow a straight line and can travel freely around corners or through openings."},
{name:"Mind Sliver",level:0,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V",duration:"1 round",classes:["Sorcerer","Warlock","Wizard"],description:"You drive a disorienting spike of psychic energy into the mind of one creature you can see within range. The target must succeed on an Intelligence saving throw or take 1d6 psychic damage and subtract 1d4 from the next saving throw it makes before the end of your next turn.",damage:"1d6 psychic"},
{name:"Minor Illusion",level:0,school:"Illusion",castingTime:"1 action",range:"30 feet",components:"S, M (a bit of fleece)",duration:"1 minute",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"You create a sound or an image of an object within range that lasts for the duration. The illusion also ends if you dismiss it as an action or cast this spell again. If you create a sound, its volume can range from a whisper to a scream. It can be your voice, someone else's voice, a lion's roar, a beating of drums, or any other sound you choose. The sound continues unabated throughout the duration, or you can make discrete sounds at different times before the spell ends."},
{name:"Poison Spray",level:0,school:"Conjuration",castingTime:"1 action",range:"10 feet",components:"V, S",duration:"Instantaneous",classes:["Druid","Sorcerer","Warlock","Wizard"],description:"You extend your hand toward a creature you can see within range and project a puff of noxious gas from your palm. The creature must succeed on a Constitution saving throw or take 2d12 poison damage. This spell's damage increases by 1d12 when you reach 5th level (3d12), 11th level (4d12), and 17th level (5d12).",damage:"2d12 poison"},
{name:"Prestidigitation",level:0,school:"Transmutation",castingTime:"1 action",range:"10 feet",components:"V, S",duration:"Up to 1 hour",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"This spell is a minor magical trick that novice spellcasters use for practice. You create one of the following magical effects within range: You create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor. You instantaneously light or snuff out a candle, a torch, or a small campfire. You instantaneously clean or soil an object no larger than 1 cubic foot. You chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour. You make a color, a small mark, or a symbol appear on an object or a surface for 1 hour. You create a nonmagical trinket or an illusory image that can fit in your hand and that lasts until the end of your next turn."},
{name:"Ray of Frost",level:0,school:"Evocation",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 1d8 cold damage, and its speed is reduced by 10 feet until the start of your next turn. The spell's damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).",damage:"1d8 cold"},
{name:"Sacred Flame",level:0,school:"Evocation",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Instantaneous",classes:["Cleric"],description:"Flame-like radiance descends on a creature that you can see within range. The target must succeed on a Dexterity saving throw or take 1d8 radiant damage. The target gains no benefit from cover for this saving throw. The spell's damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).",damage:"1d8 radiant"},
{name:"Shillelagh",level:0,school:"Transmutation",castingTime:"1 bonus action",range:"Touch",components:"V, S, M (mistletoe, a shamrock leaf, and a club or quarterstaff)",duration:"1 minute",classes:["Druid"],description:"The wood of a club or quarterstaff you are holding is imbued with nature's power. For the duration, you can use your spellcasting ability instead of Strength for the attack and damage rolls of melee attacks using that weapon, and the weapon's damage die becomes a d8. The weapon also becomes magical, if it isn't already. The spell ends if you cast it again or if you let go of the weapon."},
{name:"Shocking Grasp",level:0,school:"Evocation",castingTime:"1 action",range:"Touch",components:"V, S",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"Lightning springs from your hand to deliver a shock to a creature you try to touch. Make a melee spell attack against the target. You have advantage on the attack roll if the target is wearing armor made of metal. On a hit, the target takes 1d8 lightning damage, and it can't take reactions until the start of its next turn. The spell's damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).",damage:"1d8 lightning"},
{name:"Sword Burst",level:0,school:"Conjuration",castingTime:"1 action",range:"Self (5-foot radius)",components:"V",duration:"Instantaneous",classes:["Sorcerer","Warlock","Wizard"],description:"You create a momentary circle of spectral blades that sweep around you. All other creatures within 5 feet of you must succeed on a Dexterity saving throw or take 1d6 force damage. This spell's damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).",damage:"1d6 force"},
{name:"Thaumaturgy",level:0,school:"Transmutation",castingTime:"1 action",range:"30 feet",components:"V",duration:"Up to 1 minute",classes:["Cleric"],description:"You manifest a minor wonder, a sign of supernatural power, within range. You create one of the following magical effects within range: Your voice booms up to three times as loud as normal for 1 minute. You cause flames to flicker, brighten, dim, or change color for 1 minute. You cause harmless tremors in the ground for 1 minute. You create an instantaneous sound that originates from a point of your choice within range, such as a rumble of thunder, the cry of a raven, or ominous whispers. You instantaneously cause an unlocked door or window to fly open or slam shut. You alter the appearance of your eyes for 1 minute."},
{name:"Thunderclap",level:0,school:"Evocation",castingTime:"1 action",range:"Self (5-foot radius)",components:"S",duration:"Instantaneous",classes:["Bard","Druid","Sorcerer","Warlock","Wizard"],description:"You create a burst of thunderous sound that can be heard up to 100 feet away. Each creature within range, other than you, must make a Constitution saving throw or take 1d6 thunder damage. The spell's damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6)."},
{name:"Toll the Dead",level:0,school:"Necromancy",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Instantaneous",classes:["Cleric","Warlock","Wizard"],description:"You point at one creature you can see within range, and the sound of a dolorous bell fills the air around it for a moment. The target must succeed on a Wisdom saving throw or take 1d8 necrotic damage. If the target is missing any of its hit points, it instead takes 1d12 necrotic damage. The spell's damage increases by one die when you reach 5th level (2d8 or 2d12), 11th level (3d8 or 3d12), and 17th level (4d8 or 4d12).",damage:"1d8 or 1d12 necrotic"},
{name:"True Strike",level:0,school:"Divination",castingTime:"1 action",range:"30 feet",components:"S",duration:"Concentration, up to 1 round",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"You extend your hand and point a finger at a target in range. Your magic grants you a brief insight into the target's defenses. On your next turn, you gain advantage on your first attack roll against the target, provided that this spell hasn't ended."},
{name:"Vicious Mockery",level:0,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V",duration:"Instantaneous",classes:["Bard"],description:"You unleash a string of insults laced with subtle enchantments at a creature you can see within range. If the target can hear you (though it need not understand you), it must succeed on a Wisdom saving throw or take 1d4 psychic damage and have disadvantage on the next attack roll it makes before the end of its next turn. This spell's damage increases by 1d4 when you reach 5th level (2d4), 11th level (3d4), and 17th level (4d4).",damage:"1d4 psychic"},

// LEVEL 1
{name:"Alarm",level:1,school:"Abjuration",castingTime:"1 minute (ritual)",range:"30 feet",components:"V, S, M (a tiny bell and a piece of fine silver wire)",duration:"8 hours",classes:["Ranger","Wizard"],description:"You set an alarm against unwanted intrusion. Choose a door, a window, or an area within range that is no larger than a 20-foot cube. Until the spell ends, an alarm alerts you whenever a Tiny or larger creature touches or enters the warded area. When you cast the spell, you can designate creatures that won't set off the alarm. You also choose whether the alarm is mental or audible."},
{name:"Armor of Agathys",level:1,school:"Abjuration",castingTime:"1 action",range:"Self",components:"V, S, M (a cup of water)",duration:"1 hour",classes:["Warlock"],description:"A protective magical force surrounds you, manifesting as a spectral frost that covers you and your gear. You gain 5 temporary hit points for the duration. If a creature hits you with a melee attack while you have these hit points, the creature takes 5 cold damage. This spell's temporary hit points and the cold damage both increase by 5 for each slot level above 1st.",damage:"5 cold (to attacker)"},
{name:"Arms of Hadar",level:1,school:"Conjuration",castingTime:"1 action",range:"Self (10-foot radius)",components:"V, S",duration:"Instantaneous",classes:["Warlock"],description:"You invoke the power of Hadar, the Dark Hunger. Tendrils of dark energy erupt from you and batter all creatures within 10 feet of you. Each creature in that area must make a Strength saving throw. On a failed save, a target takes 2d6 necrotic damage and can't take reactions until its next turn. On a successful save, the creature takes half damage, but suffers no other effect.",damage:"2d6 necrotic"},
{name:"Bane",level:1,school:"Enchantment",castingTime:"1 action",range:"30 feet",components:"V, S, M (a drop of blood)",duration:"Concentration, up to 1 minute",classes:["Bard","Cleric","Paladin"],description:"Up to three creatures of your choice that you can see within range must make Charisma saving throws. Whenever a target that fails this saving throw makes an attack roll or a saving throw before the spell ends, the target must roll a d4 and subtract the number rolled from the attack roll or saving throw."},
{name:"Burning Hands",level:1,school:"Evocation",castingTime:"1 action",range:"Self (15-foot cone)",components:"V, S",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"As you hold your hands with thumbs touching and fingers spread, a thin sheet of flames shoots forth from your outstretched fingertips. Each creature in a 15-foot cone must make a Dexterity saving throw. A creature takes 3d6 fire damage on a failed save, or half as much damage on a successful one. The fire ignites any flammable objects in the area that aren't being worn or carried. At Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.",damage:"3d6 fire"},
{name:"Charm Person",level:1,school:"Enchantment",castingTime:"1 action",range:"30 feet",components:"V, S",duration:"1 hour",classes:["Bard","Druid","Sorcerer","Warlock","Wizard"],description:"You attempt to charm a humanoid you can see within range. It must make a Wisdom saving throw, and does so with advantage if you or your companions are fighting it. If it fails the saving throw, it is charmed by you until the spell ends or until you or your companions do anything harmful to it. The charmed creature regards you as a friendly acquaintance. When the spell ends, the creature knows it was charmed by you."},
{name:"Color Spray",level:1,school:"Illusion",castingTime:"1 action",range:"Self (15-foot cone)",components:"V, S, M (a pinch of powder or sand that is colored red, yellow, and blue)",duration:"1 round",classes:["Sorcerer","Wizard"],description:"A dazzling array of flashing, colored light springs from your hand. Roll 6d10; the total is how many hit points of creatures this spell can affect. Creatures in a 15-foot cone originating from you are affected in ascending order of their current hit points (ignoring unconscious creatures and creatures that can't see)."},
{name:"Command",level:1,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V",duration:"1 round",classes:["Cleric","Paladin"],description:"You speak a one-word command to a creature you can see within range. The target must succeed on a Wisdom saving throw or follow the command on its next turn. The spell has no effect if the target is undead, if it doesn't understand your language, or if your command is directly harmful to it."},
{name:"Comprehend Languages",level:1,school:"Divination",castingTime:"1 action (ritual)",range:"Self",components:"V, S, M (a pinch of soot and salt)",duration:"1 hour",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"For the duration, you understand the literal meaning of any spoken language that you hear. You also understand any written language that you see, but you must be touching the surface on which the words are written. It takes about 1 minute to read one page of text."},
{name:"Cure Wounds",level:1,school:"Evocation",castingTime:"1 action",range:"Touch",components:"V, S",duration:"Instantaneous",classes:["Bard","Cleric","Druid","Paladin","Ranger"],description:"A creature you touch regains a number of hit points equal to 1d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs. At Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d8 for each slot level above 1st.",damage:"1d8+mod healing"},
{name:"Detect Magic",level:1,school:"Divination",castingTime:"1 action (ritual)",range:"Self",components:"V, S",duration:"Concentration, up to 10 minutes",classes:["Bard","Cleric","Druid","Paladin","Ranger","Sorcerer","Wizard"],description:"For the duration, you sense the presence of magic within 30 feet of you. If you sense magic in this way, you can use your action to see a faint aura around any visible creature or object in the area that bears magic, and you learn its school of magic, if any."},
{name:"Disguise Self",level:1,school:"Illusion",castingTime:"1 action",range:"Self",components:"V, S",duration:"1 hour",classes:["Bard","Sorcerer","Wizard"],description:"You make yourself—including your clothing, armor, weapons, and other belongings on your person—look different until the spell ends or until you use your action to dismiss it. You can seem 1 foot shorter or taller and can appear thin, fat, or in between. You can't change your body type, so you must adopt a form that has the same basic arrangement of limbs. Otherwise, the extent of the illusion is up to you."},
{name:"Dissonant Whispers",level:1,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V",duration:"Instantaneous",classes:["Bard"],description:"You whisper a discordant melody that only one creature of your choice within range can hear, wracking it with terrible pain. The target must make a Wisdom saving throw. On a failed save, it takes 3d6 psychic damage and must immediately use its reaction, if available, to move as far as its speed allows away from you. The creature doesn't move into obviously dangerous ground, such as a fire or a pit. On a successful save, the target takes half as much damage and doesn't have to move away. A deafened creature automatically succeeds on the saving throw.",damage:"3d6 psychic"},
{name:"Divine Favor",level:1,school:"Evocation",castingTime:"1 bonus action",range:"Self",components:"V, S",duration:"Concentration, up to 1 minute",classes:["Paladin"],description:"Your prayer empowers you with divine radiance. Until the spell ends, your weapon attacks deal an extra 1d4 radiant damage on a hit.",damage:"+1d4 radiant"},
{name:"Expeditious Retreat",level:1,school:"Transmutation",castingTime:"1 bonus action",range:"Self",components:"V, S",duration:"Concentration, up to 10 minutes",classes:["Sorcerer","Warlock","Wizard"],description:"This spell allows you to move at an incredible pace. When you cast this spell, and then as a bonus action on each of your turns until the spell ends, you can take the Dash action."},
{name:"Faerie Fire",level:1,school:"Evocation",castingTime:"1 action",range:"60 feet",components:"V",duration:"Concentration, up to 1 minute",classes:["Bard","Druid"],description:"Each object in a 20-foot cube within range is outlined in blue, green, or violet light (your choice). Any creature in the area when the spell is cast is also outlined in light if it fails a Dexterity saving throw. For the duration, objects and affected creatures shed dim light in a 10-foot radius. Any attack roll against an affected creature or object has advantage if the attacker can see it, and the affected creature or object can't benefit from being invisible."},
{name:"False Life",level:1,school:"Necromancy",castingTime:"1 action",range:"Self",components:"V, S, M (a small amount of alcohol or distilled spirits)",duration:"1 hour",classes:["Sorcerer","Wizard"],description:"Bolstering yourself with a necromantic facsimile of life, you gain 1d4 + 4 temporary hit points for the duration."},
{name:"Feather Fall",level:1,school:"Transmutation",castingTime:"1 reaction",range:"60 feet",components:"V, M (a small feather or piece of down)",duration:"1 minute",classes:["Bard","Sorcerer","Wizard"],description:"Choose up to five falling creatures within range. A falling creature's rate of descent slows to 60 feet per round until the spell ends. If the creature lands before the spell ends, it takes no falling damage and can land on its feet, and the spell ends for that creature."},
{name:"Find Familiar",level:1,school:"Conjuration",castingTime:"1 hour (ritual)",range:"10 feet",components:"V, S, M (10 gp worth of charcoal, incense, and herbs that must be consumed by fire in a brass brazier)",duration:"Instantaneous",classes:["Wizard"],description:"You gain the service of a familiar, a spirit that takes an animal form you choose: bat, cat, crab, frog (toad), hawk, lizard, octopus, owl, poisonous snake, fish (quipper), rat, raven, sea horse, spider, or weasel. Appearing in an unoccupied space within range, the familiar has the statistics of the chosen form, though it is a celestial, fey, or fiend (your choice) instead of a beast."},
{name:"Fog Cloud",level:1,school:"Conjuration",castingTime:"1 action",range:"120 feet",components:"V, S",duration:"Concentration, up to 1 hour",classes:["Druid","Ranger","Sorcerer","Wizard"],description:"You create a 20-foot-radius sphere of fog centered on a point within range. The sphere spreads around corners, and its area is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it."},
{name:"Grease",level:1,school:"Conjuration",castingTime:"1 action",range:"60 feet",components:"V, S, M (a bit of pork rind or butter)",duration:"1 minute",classes:["Wizard"],description:"Slick grease covers the ground in a 10-foot square centered on a point within range and turns it into difficult terrain for the duration. When the grease appears, each creature standing in its area must succeed on a Dexterity saving throw or fall prone. A creature that enters the area or ends its turn there must also succeed on a Dexterity saving throw or fall prone."},
{name:"Healing Word",level:1,school:"Evocation",castingTime:"1 bonus action",range:"60 feet",components:"V",duration:"Instantaneous",classes:["Bard","Cleric","Druid"],description:"A creature of your choice that you can see within range regains hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs. At Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d4 for each slot level above 1st.",damage:"1d4+mod healing"},
{name:"Hex",level:1,school:"Enchantment",castingTime:"1 bonus action",range:"90 feet",components:"V, S, M (the petrified eye of a newt)",duration:"Concentration, up to 1 hour",classes:["Warlock"],description:"You place a curse on a creature that you can see within range. Until the spell ends, you deal an extra 1d6 necrotic damage to the target whenever you hit it with an attack. Also, choose one ability when you cast the spell. The target has disadvantage on ability checks made with the chosen ability. If the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to curse a new creature.",damage:"+1d6 necrotic"},
{name:"Hunter's Mark",level:1,school:"Divination",castingTime:"1 bonus action",range:"90 feet",components:"V",duration:"Concentration, up to 1 hour",classes:["Ranger","Paladin"],description:"You choose a creature you can see within range and mystically mark it as your quarry. Until the spell ends, you deal an extra 1d6 damage to the target whenever you hit it with a weapon attack, and you have advantage on any Wisdom (Perception) or Wisdom (Survival) check you make to find it. If the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to mark a new creature.",damage:"+1d6 damage"},
{name:"Identify",level:1,school:"Divination",castingTime:"1 minute (ritual)",range:"Touch",components:"V, S, M (a pearl worth at least 100 gp and an owl feather)",duration:"Instantaneous",classes:["Bard","Wizard"],description:"You choose one object that you must touch throughout the casting of the spell. If it is a magic item or some other magic-imbued object, you learn its properties and how to use them, whether it requires attunement to use, and how many charges it has, if any. You learn whether any spells are affecting the item and what they are. If the item was created by a spell, you learn which spell created it."},
{name:"Inflict Wounds",level:1,school:"Necromancy",castingTime:"1 action",range:"Touch",components:"V, S",duration:"Instantaneous",classes:["Cleric"],description:"Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 necrotic damage. At Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.",damage:"3d10 necrotic"},
{name:"Jump",level:1,school:"Transmutation",castingTime:"1 action",range:"Touch",components:"V, S, M (a grasshopper's hind leg)",duration:"1 minute",classes:["Druid","Ranger","Sorcerer","Wizard"],description:"You touch a creature. The creature's jump distance is tripled until the spell ends."},
{name:"Longstrider",level:1,school:"Transmutation",castingTime:"1 action",range:"Touch",components:"V, S, M (a pinch of dirt)",duration:"1 hour",classes:["Bard","Druid","Ranger","Wizard"],description:"You touch a creature. The target's speed increases by 10 feet until the spell ends."},
{name:"Mage Armor",level:1,school:"Abjuration",castingTime:"1 action",range:"Touch",components:"V, S, M (a piece of cured leather)",duration:"8 hours",classes:["Sorcerer","Wizard"],description:"You touch a willing creature who isn't wearing armor, and a protective magical force surrounds it until the spell ends. The target's base AC becomes 13 + its Dexterity modifier. The spell ends if the target dons armor or if you dismiss the spell as an action."},
{name:"Magic Missile",level:1,school:"Evocation",castingTime:"1 action",range:"120 feet",components:"V, S",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"You create three glowing darts of magical force. Each dart hits a creature of your choice that you can see within range. A dart deals 1d4 + 1 force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several. At Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the spell creates one more dart for each slot level above 1st.",damage:"3× (1d4+1) force"},
{name:"Protection from Evil and Good",level:1,school:"Abjuration",castingTime:"1 action",range:"Touch",components:"V, S, M (holy water or powdered silver and iron, which the spell consumes)",duration:"Concentration, up to 10 minutes",classes:["Cleric","Druid","Paladin","Warlock","Wizard"],description:"Until the spell ends, one willing creature you touch is protected against certain types of creatures: aberrations, celestials, elementals, fey, fiends, and undead. The protection grants several benefits. Creatures of those types have disadvantage on attack rolls against the target. The target also can't be charmed, frightened, or possessed by them."},
{name:"Ray of Sickness",level:1,school:"Necromancy",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"A ray of sickening greenish energy lashes out toward a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 2d8 poison damage and must make a Constitution saving throw. On a failed save, it is also poisoned until the end of your next turn. At Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.",damage:"2d8 poison"},
{name:"Sanctuary",level:1,school:"Abjuration",castingTime:"1 bonus action",range:"30 feet",components:"V, S, M (a small silver mirror)",duration:"1 minute",classes:["Cleric","Paladin"],description:"You ward a creature within range against attack. Until the spell ends, any creature who targets the warded creature with an attack or a harmful spell must first make a Wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or spell. This spell doesn't protect the warded creature from area effects, such as the explosion of a fireball."},
{name:"Shield",level:1,school:"Abjuration",castingTime:"1 reaction",range:"Self",components:"V, S",duration:"1 round",classes:["Sorcerer","Wizard","Warlock"],description:"An invisible barrier of magical force appears and protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from magic missile."},
{name:"Shield of Faith",level:1,school:"Abjuration",castingTime:"1 bonus action",range:"60 feet",components:"V, S, M (a small parchment with a bit of holy text written on it)",duration:"Concentration, up to 10 minutes",classes:["Cleric","Paladin"],description:"A shimmering field appears and surrounds a creature of your choice within range, granting it a +2 bonus to AC for the duration."},
{name:"Silent Image",level:1,school:"Illusion",castingTime:"1 action",range:"60 feet",components:"V, S, M (a bit of fleece)",duration:"Concentration, up to 10 minutes",classes:["Bard","Sorcerer","Wizard"],description:"You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15-foot cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn't accompanied by sound, smell, or other sensory effects."},
{name:"Sleep",level:1,school:"Enchantment",castingTime:"1 action",range:"90 feet",components:"V, S, M (a pinch of fine sand, rose petals, or a cricket)",duration:"1 minute",classes:["Bard","Sorcerer","Wizard"],description:"This spell sends creatures into a magical slumber. Roll 5d8; the total is how many hit points of creatures this spell can affect. Creatures within 20 feet of a point you choose within range are affected in ascending order of their current hit points (ignoring unconscious creatures). At Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d8 for each slot level above 1st."},
{name:"Thunderwave",level:1,school:"Evocation",castingTime:"1 action",range:"Self (15-foot cube)",components:"V, S",duration:"Instantaneous",classes:["Bard","Druid","Sorcerer","Wizard"],description:"A wave of thunderous force sweeps out from you. Each creature in a 15-foot cube originating from you must make a Constitution saving throw. On a failed save, a creature takes 2d8 thunder damage and is pushed 10 feet away from you. On a successful save, the creature takes half as much damage and isn't pushed. At Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.",damage:"2d8 thunder"},
{name:"Witch Bolt",level:1,school:"Evocation",castingTime:"1 action",range:"30 feet",components:"V, S, M (a twig from a tree that has been struck by lightning)",duration:"Concentration, up to 1 minute",classes:["Sorcerer","Warlock","Wizard"],description:"A beam of crackling, blue energy lances out toward a creature within range, forming a sustained arc of lightning between you and the target. Make a ranged spell attack against that creature. On a hit, the target takes 1d12 lightning damage, and on each of your turns for the duration, you can use your action to deal 1d12 lightning damage to the target automatically. The spell ends if you use your action to do anything else. At Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the initial damage increases by 1d12 for each slot level above 1st.",damage:"1d12 lightning"},
{name:"Wrathful Smite",level:1,school:"Evocation",castingTime:"1 bonus action",range:"Self",components:"V",duration:"Concentration, up to 1 minute",classes:["Paladin","Warlock"],description:"The next time you hit with a melee weapon attack during this spell's duration, your attack deals an extra 1d6 psychic damage. Additionally, if the target is a creature, it must make a Wisdom saving throw or be frightened of you until the spell ends. As an action, the creature can make a Wisdom check against your spell save DC to steel its resolve and end this spell.",damage:"+1d6 psychic"},

// LEVEL 2
{name:"Aid",level:2,school:"Abjuration",castingTime:"1 action",range:"30 feet",components:"V, S, M (a tiny strip of white cloth)",duration:"8 hours",classes:["Cleric","Paladin"],description:"Your spell bolsters your allies with toughness and resolve. Choose up to three creatures within range. Each target's hit point maximum and current hit points increase by 5 for the duration. At Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, a target's hit points increase by an additional 5 for each slot level above 2nd."},
{name:"Alter Self",level:2,school:"Transmutation",castingTime:"1 action",range:"Self",components:"V, S",duration:"Concentration, up to 1 hour",classes:["Druid","Sorcerer","Wizard"],description:"You assume a different form. When you cast the spell, choose one of the following options, the effects of which last for the duration of the spell. While the spell lasts, you can end one option as an action to gain the benefits of a different one. Aquatic Adaptation, Change Appearance, or Natural Weapons."},
{name:"Barkskin",level:2,school:"Transmutation",castingTime:"1 action",range:"Touch",components:"V, S, M (a handful of oak bark)",duration:"Concentration, up to 1 hour",classes:["Druid","Ranger"],description:"You touch a willing creature. Until the spell ends, the target's skin has a rough, bark-like appearance, and the target's AC can't be less than 16, regardless of what kind of armor it is wearing."},
{name:"Blindness/Deafness",level:2,school:"Necromancy",castingTime:"1 action",range:"30 feet",components:"V",duration:"1 minute",classes:["Bard","Cleric","Sorcerer","Wizard"],description:"You can blind or deafen a foe. Choose one creature that you can see within range to make a Constitution saving throw. If it fails, the target is either blinded or deafened (your choice) for the duration. At the end of each of its turns, the target can make a Constitution saving throw. On a success, the spell ends."},
{name:"Blur",level:2,school:"Illusion",castingTime:"1 action",range:"Self",components:"V",duration:"Concentration, up to 1 minute",classes:["Sorcerer","Wizard","Warlock"],description:"Your body becomes blurred, shifting and wavering to all who can see you. For the duration, any creature has disadvantage on attack rolls against you. An attacker is immune to this effect if it doesn't rely on sight, as with blindsight, or can see through illusions, as with truesight."},
{name:"Branding Smite",level:2,school:"Evocation",castingTime:"1 bonus action",range:"Self",components:"V",duration:"Concentration, up to 1 minute",classes:["Paladin","Warlock"],description:"The next time you hit a creature with a weapon attack before this spell ends, the weapon gleams with astral radiance as you strike. The attack deals an extra 2d6 radiant damage to the target, which becomes visible if it's invisible, and the target sheds dim light in a 5-foot radius and can't become invisible until the spell ends. At Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, the extra damage increases by 1d6 for each slot level above 2nd.",damage:"2d6 radiant"},
{name:"Calm Emotions",level:2,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Concentration, up to 1 minute",classes:["Bard","Cleric"],description:"You attempt to suppress strong emotions in a group of people. Each humanoid in a 20-foot-radius sphere centered on a point you choose within range must make a Charisma saving throw; a creature can choose to fail this saving throw if it wishes."},
{name:"Darkness",level:2,school:"Evocation",castingTime:"1 action",range:"60 feet",components:"V, M (bat fur and a drop of pitch or piece of coal)",duration:"Concentration, up to 10 minutes",classes:["Sorcerer","Warlock","Wizard"],description:"Magical darkness spreads from a point you choose within range to fill a 15-foot-radius sphere for the duration. The darkness spreads around corners. A creature with darkvision can't see through this magical darkness, and nonmagical light can't illuminate it."},
{name:"Darkvision",level:2,school:"Transmutation",castingTime:"1 action",range:"Touch",components:"V, S, M (either a pinch of dried carrot or an agate)",duration:"8 hours",classes:["Druid","Ranger","Sorcerer","Wizard"],description:"You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has darkvision out to a range of 60 feet."},
{name:"Enhance Ability",level:2,school:"Transmutation",castingTime:"1 action",range:"Touch",components:"V, S, M (fur or a feather from a beast)",duration:"Concentration, up to 1 hour",classes:["Bard","Cleric","Druid","Sorcerer","Wizard"],description:"You touch a creature and bestow upon it a magical enhancement. Choose one of the following effects; the target gains that effect until the spell ends. Bear's Endurance, Bull's Strength, Cat's Grace, Eagle's Splendor, Fox's Cunning, or Owl's Wisdom."},
{name:"Enlarge/Reduce",level:2,school:"Transmutation",castingTime:"1 action",range:"30 feet",components:"V, S, M (a pinch of powdered iron)",duration:"Concentration, up to 1 minute",classes:["Sorcerer","Wizard"],description:"You cause a creature or an object you can see within range to grow larger or smaller for the duration. Choose either a creature or an object that is neither worn nor carried. If the target is unwilling, it can make a Constitution saving throw. On a success, the spell has no effect."},
{name:"Enthrall",level:2,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"1 minute",classes:["Bard","Warlock"],description:"You weave a distracting string of words, causing creatures of your choice that you can see within range and that can hear you to make a Wisdom saving throw. Any creature that can't be charmed succeeds on this saving throw automatically, and if you or your companions are fighting a creature, it has advantage on the saving throw."},
{name:"Find Traps",level:2,school:"Divination",castingTime:"1 action",range:"120 feet",components:"V, S",duration:"Instantaneous",classes:["Cleric","Druid","Ranger"],description:"You sense the presence of any trap within range that is within line of sight. A trap, for the purpose of this spell, includes anything that would inflict a sudden or unexpected effect you consider harmful or undesirable, which was specifically intended as such by its creator."},
{name:"Flaming Sphere",level:2,school:"Conjuration",castingTime:"1 action",range:"60 feet",components:"V, S, M (a bit of tallow, a pinch of brimstone, and a dusting of powdered iron)",duration:"Concentration, up to 1 minute",classes:["Druid","Wizard"],description:"A 5-foot-diameter sphere of fire appears in an unoccupied space of your choice within range and lasts for the duration. Any creature that ends its turn within 5 feet of the sphere must make a Dexterity saving throw. The creature takes 2d6 fire damage on a failed save, or half as much damage on a successful one.",damage:"2d6 fire"},
{name:"Heat Metal",level:2,school:"Transmutation",castingTime:"1 action",range:"60 feet",components:"V, S, M (a piece of iron and a flame)",duration:"Concentration, up to 1 minute",classes:["Bard","Druid"],description:"Choose a manufactured metal object, such as a metal weapon or a suit of heavy or medium metal armor, that you can see within range. You cause the object to glow red-hot. Any creature in physical contact with the object takes 2d8 fire damage when you cast the spell. Until the spell ends, you can use a bonus action on each of your subsequent turns to deal this damage again.",damage:"2d8 fire"},
{name:"Hold Person",level:2,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V, S, M (a small, straight piece of iron)",duration:"Concentration, up to 1 minute",classes:["Bard","Cleric","Druid","Sorcerer","Warlock","Wizard","Paladin"],description:"Choose a humanoid that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target. At Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, you can target one additional humanoid for each slot level above 2nd."},
{name:"Invisibility",level:2,school:"Illusion",castingTime:"1 action",range:"Touch",components:"V, S, M (an eyelash encased in gum arabic)",duration:"Concentration, up to 1 hour",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"A creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target's person. The spell ends for a target that attacks or casts a spell. At Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd."},
{name:"Knock",level:2,school:"Transmutation",castingTime:"1 action",range:"60 feet",components:"V",duration:"Instantaneous",classes:["Bard","Sorcerer","Wizard"],description:"Choose an object that you can see within range. The object can be a door, a box, a chest, a set of manacles, a padlock, or another object that contains a mundane or magical means that prevents access. A target that is held shut by a mundane lock or that is stuck or barred becomes unlocked, unstuck, or unbarred."},
{name:"Levitate",level:2,school:"Transmutation",castingTime:"1 action",range:"60 feet",components:"V, S, M (either a small leather loop or a piece of golden wire bent into a cup shape with a long shank on one end)",duration:"Concentration, up to 10 minutes",classes:["Sorcerer","Wizard"],description:"One creature or object of your choice that you can see within range rises vertically, up to 20 feet, and remains suspended there for the duration. The spell can levitate a target that weighs up to 500 pounds."},
{name:"Misty Step",level:2,school:"Conjuration",castingTime:"1 bonus action",range:"Self",components:"V",duration:"Instantaneous",classes:["Sorcerer","Warlock","Wizard","Paladin"],description:"Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space that you can see."},
{name:"Moonbeam",level:2,school:"Evocation",castingTime:"1 action",range:"120 feet",components:"V, S, M (several seeds of any moonseed plant and a piece of opalescent feldspar)",duration:"Concentration, up to 1 minute",classes:["Druid"],description:"A silvery beam of pale light shines down in a 5-foot-radius, 40-foot-high cylinder centered on a point within range. Until the spell ends, dim light fills the cylinder. When a creature enters the spell's area for the first time on a turn or starts its turn there, it is engulfed in ghostly flames that cause searing pain, and it must make a Constitution saving throw. It takes 2d10 radiant damage on a failed save, or half as much damage on a successful one.",damage:"2d10 radiant"},
{name:"Pass without Trace",level:2,school:"Abjuration",castingTime:"1 action",range:"Self",components:"V, S, M (ashes from a burned leaf of mistletoe and a sprig of spruce)",duration:"Concentration, up to 1 hour",classes:["Druid","Ranger"],description:"A veil of shadows and silence radiates from you, masking you and your companions from detection. For the duration, each creature you choose within 30 feet of you (including you) has a +10 bonus to Dexterity (Stealth) checks and can't be tracked except by magical means."},
{name:"Prayer of Healing",level:2,school:"Evocation",castingTime:"10 minutes",range:"30 feet",components:"V",duration:"Instantaneous",classes:["Cleric","Paladin"],description:"Up to six creatures of your choice that you can see within range each regain hit points equal to 2d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs. At Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, the healing increases by 1d8 for each slot level above 2nd.",damage:"2d8+mod healing"},
{name:"Protection from Poison",level:2,school:"Abjuration",castingTime:"1 action",range:"Touch",components:"V, S",duration:"1 hour",classes:["Cleric","Druid","Paladin","Ranger"],description:"You touch a creature. If it is poisoned, you neutralize the poison. If more than one poison afflicts the target, you neutralize one poison that you know is present, or you neutralize one at random. For the duration, the target has advantage on saving throws against being poisoned, and it has resistance to poison damage."},
{name:"Scorching Ray",level:2,school:"Evocation",castingTime:"1 action",range:"120 feet",components:"V, S",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"You create three rays of fire and hurl them at targets within range. You can hurl them at one target or several. Make a ranged spell attack for each ray. On a hit, the target takes 2d6 fire damage. At Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, you create one additional ray for each slot level above 2nd.",damage:"2d6 fire (per ray)"},
{name:"See Invisibility",level:2,school:"Divination",castingTime:"1 action",range:"Self",components:"V, S, M (a pinch of talc and a small sprinkling of powdered silver)",duration:"1 hour",classes:["Bard","Sorcerer","Wizard"],description:"For the duration, you see invisible creatures and objects as if they were visible, and you can see into the Ethereal Plane, out to a range of 60 feet."},
{name:"Shatter",level:2,school:"Evocation",castingTime:"1 action",range:"60 feet",components:"V, S, M (a chip of mica)",duration:"Instantaneous",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"A sudden loud ringing noise, painfully intense, erupts from a point of your choice within range. Each creature in a 10-foot-radius sphere centered on that point must make a Constitution saving throw. A creature takes 3d8 thunder damage on a failed save, or half as much damage on a successful one. At Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for each slot level above 2nd.",damage:"3d8 thunder"},
{name:"Spider Climb",level:2,school:"Transmutation",castingTime:"1 action",range:"Touch",components:"V, S, M (a drop of bitumen and a spider)",duration:"Concentration, up to 1 hour",classes:["Sorcerer","Warlock","Wizard"],description:"Until the spell ends, one willing creature you touch gains the ability to move up, down, and across vertical surfaces and upside down along ceilings, while leaving its hands free. The target also gains a climbing speed equal to its walking speed."},
{name:"Suggestion",level:2,school:"Enchantment",castingTime:"1 action",range:"30 feet",components:"V, M (a snake's tongue and either a bit of honeycomb or a drop of sweet oil)",duration:"Concentration, up to 8 hours",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"You suggest a course of activity (limited to a sentence or two) and magically influence a creature you can see within range that can hear and understand you. Creatures that can't be charmed are immune to this effect. The suggestion must be worded in such a manner as to make the course of action sound reasonable."},
{name:"Web",level:2,school:"Conjuration",castingTime:"1 action",range:"60 feet",components:"V, S, M (a bit of spiderweb)",duration:"Concentration, up to 1 hour",classes:["Sorcerer","Wizard"],description:"You conjure a mass of thick, sticky webbing at a point of your choice within range. The webs fill a 20-foot cube from that point for the duration. The webs are difficult terrain and lightly obscure their area. Each creature that starts its turn in the webs or that enters them during its turn must make a Dexterity saving throw."},

// LEVEL 3
{name:"Animate Dead",level:3,school:"Necromancy",castingTime:"1 minute",range:"10 feet",components:"V, S, M (a drop of blood, a piece of flesh, and a pinch of bone dust)",duration:"Instantaneous",classes:["Cleric","Wizard"],description:"This spell creates an undead servant. Choose a pile of bones or a corpse of a Medium or Small humanoid within range. Your spell imbues the target with a foul mimicry of life, raising it as an undead creature."},
{name:"Bestow Curse",level:3,school:"Necromancy",castingTime:"1 action",range:"Touch",components:"V, S",duration:"Concentration, up to 1 minute",classes:["Bard","Cleric","Wizard"],description:"You touch a creature, and that creature must succeed on a Wisdom saving throw or become cursed for the duration of the spell. When you cast this spell, choose the nature of the curse from the following options: Disadvantage on ability checks and saving throws made with the chosen ability score. Disadvantage on attack rolls against you. Must make a Wisdom saving throw at the start of each turn."},
{name:"Blink",level:3,school:"Transmutation",castingTime:"1 action",range:"Self",components:"V, S",duration:"1 minute",classes:["Sorcerer","Wizard","Warlock"],description:"Roll a d20 at the end of each of your turns for the duration of the spell. On a roll of 11 or higher, you vanish from your current plane of existence and appear in the Ethereal Plane. At the start of your next turn, and when the spell ends if you are on the Ethereal Plane, you return to an unoccupied space of your choice that you can see within 10 feet of the space you vanished from."},
{name:"Call Lightning",level:3,school:"Conjuration",castingTime:"1 action",range:"120 feet",components:"V, S",duration:"Concentration, up to 10 minutes",classes:["Druid"],description:"A storm cloud appears in the shape of a cylinder that is 10 feet tall with a 60-foot radius, centered on a point you can see 100 feet directly above you. The spell fails if you can't see a point in the air where the storm cloud could appear. When you cast the spell, choose a point you can see within range. The cloud moves to that point. A bolt of lightning flashes down from the cloud to that point. Each creature within 5 feet of that point must make a Dexterity saving throw. A creature takes 3d10 lightning damage on a failed save, or half as much damage on a successful one.",damage:"3d10 lightning"},
{name:"Clairvoyance",level:3,school:"Divination",castingTime:"10 minutes",range:"1 mile",components:"V, S, M (a focus worth at least 100 gp, either a jeweled horn for hearing or a glass eye for seeing)",duration:"Concentration, up to 10 minutes",classes:["Bard","Cleric","Sorcerer","Wizard"],description:"You create an invisible sensor within range in a location familiar to you (a place you have visited or seen before) or in an obvious location that is unfamiliar to you (such as behind a door, around a corner, or in a grove of trees). The sensor remains in place for the duration, and it can't be attacked or otherwise interacted with."},
{name:"Counterspell",level:3,school:"Abjuration",castingTime:"1 reaction",range:"60 feet",components:"S",duration:"Instantaneous",classes:["Sorcerer","Warlock","Wizard"],description:"You attempt to interrupt a creature in the process of casting a spell. If the creature is casting a spell of 3rd level or lower, its spell fails and has no effect. If it is casting a spell of 4th level or higher, make an ability check using your spellcasting ability. The DC equals 10 + the spell's level. On a success, the creature's spell fails and has no effect."},
{name:"Crusader's Mantle",level:3,school:"Evocation",castingTime:"1 action",range:"Self",components:"V",duration:"Concentration, up to 1 minute",classes:["Paladin"],description:"Holy power radiates from you in an aura with a 30-foot radius, awakening boldness in friendly creatures. Until the spell ends, the aura moves with you, centered on you. While in the aura, each nonhostile creature in the aura (including you) deals an extra 1d4 radiant damage when it hits with a weapon attack.",damage:"+1d4 radiant"},
{name:"Daylight",level:3,school:"Evocation",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"1 hour",classes:["Cleric","Druid","Paladin","Ranger","Sorcerer"],description:"A 60-foot-radius sphere of light spreads out from a point you choose within range. The sphere is bright light and sheds dim light for an additional 60 feet. If the point you choose is on an object you are holding or one that isn't being worn or carried, the light shines from the object with and moves with it."},
{name:"Death Ward",level:4,school:"Abjuration",castingTime:"1 action",range:"Touch",components:"V, S",duration:"8 hours",classes:["Cleric","Paladin"],description:"You touch a creature and grant it a measure of protection from death. The first time the target would drop to 0 hit points as a result of taking damage, the target instead drops to 1 hit point, and the spell ends. If the spell is still in effect when the target is subjected to an effect that would kill it instantaneously without dealing damage, that effect is instead negated against the target, and the spell ends."},
{name:"Dispel Magic",level:3,school:"Abjuration",castingTime:"1 action",range:"120 feet",components:"V, S",duration:"Instantaneous",classes:["Bard","Cleric","Druid","Paladin","Sorcerer","Warlock","Wizard"],description:"Choose any creature, object, or magical effect within range. Any spell of 3rd level or lower on the target ends. For each spell of 4th level or higher on the target, make an ability check using your spellcasting ability. The DC equals 10 + the spell's level. On a successful check, the spell ends."},
{name:"Elemental Weapon",level:3,school:"Transmutation",castingTime:"1 action",range:"Touch",components:"V, S",duration:"Concentration, up to 1 hour",classes:["Paladin","Warlock"],description:"A nonmagical weapon you touch becomes a magic weapon. Choose one of the following damage types: acid, cold, fire, lightning, or thunder. For the duration, the weapon has a +1 bonus to attack rolls and deals an extra 1d4 damage of the chosen type on a hit.",damage:"+1d4 elemental"},
{name:"Fireball",level:3,school:"Evocation",castingTime:"1 action",range:"150 feet",components:"V, S, M (a tiny ball of bat guano and sulfur)",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"A bright streak flashes from your pointing finger to a point you choose within range and then blossoms with a low roar into an explosion of flame. Each creature in a 20-foot-radius sphere centered on that point must make a Dexterity saving throw. A target takes 8d6 fire damage on a failed save, or half as much damage on a successful one. The fire spreads around corners. At Higher Levels: When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.",damage:"8d6 fire"},
{name:"Fly",level:3,school:"Transmutation",castingTime:"1 action",range:"Touch",components:"V, S, M (a wing feather from any bird)",duration:"Concentration, up to 10 minutes",classes:["Sorcerer","Warlock","Wizard"],description:"You touch a willing creature. The target gains a flying speed of 60 feet for the duration. When the spell ends, the target falls if it is still aloft, unless it can stop the fall."},
{name:"Haste",level:3,school:"Transmutation",castingTime:"1 action",range:"30 feet",components:"V, S, M (a shaving of licorice root)",duration:"Concentration, up to 1 minute",classes:["Sorcerer","Wizard","Paladin"],description:"Choose a willing creature that you can see within range. Until the spell ends, the target's speed is doubled, it gains a +2 bonus to AC, it has advantage on Dexterity saving throws, and it gains an additional action on each of its turns. That action can be used only to take the Attack (one weapon attack only), Dash, Disengage, Hide, or Use an Object action. When the spell ends, the target can't move or take actions until after its next turn, as a wave of lethargy sweeps over it."},
{name:"Hypnotic Pattern",level:3,school:"Illusion",castingTime:"1 action",range:"120 feet",components:"S, M (a glowing stick of incense or a crystal vial filled with phosphorescent material)",duration:"Concentration, up to 1 minute",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"You create a twisting pattern of colors that weaves through the air inside a 30-foot cube within range. The pattern appears for a moment and vanishes. Each creature in the area who sees the pattern must make a Wisdom saving throw. On a failed save, the creature becomes charmed for the duration. While charmed by this spell, the creature is incapacitated and has a speed of 0."},
{name:"Lightning Bolt",level:3,school:"Evocation",castingTime:"1 action",range:"Self (100-foot line)",components:"V, S, M (a bit of fur and a rod of amber, crystal, or glass)",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"A stroke of lightning forming a line 100 feet long and 5 feet wide blasts out from you in a direction you choose. Each creature in the line must make a Dexterity saving throw. A creature takes 8d6 lightning damage on a failed save, or half as much damage on a successful one. At Higher Levels: When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.",damage:"8d6 lightning"},
{name:"Mass Healing Word",level:3,school:"Evocation",castingTime:"1 bonus action",range:"60 feet",components:"V",duration:"Instantaneous",classes:["Cleric"],description:"As you call out words of restoration, up to six creatures of your choice that you can see within range regain hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs. At Higher Levels: When you cast this spell using a spell slot of 4th level or higher, the healing increases by 1d4 for each slot level above 3rd.",damage:"1d4+mod healing"},
{name:"Phantom Steed",level:3,school:"Illusion",castingTime:"1 minute (ritual)",range:"30 feet",components:"V, S",duration:"1 hour",classes:["Sorcerer","Wizard"],description:"A Large quasi-real, horse-like creature appears on the ground in an unoccupied space of your choice within range. You decide the creature's appearance, but it is equipped with a saddle, bit, and bridle. Any of the equipment created by the spell vanishes in a puff of smoke if it is carried more than 10 feet away from the steed."},
{name:"Protection from Energy",level:3,school:"Abjuration",castingTime:"1 action",range:"Touch",components:"V, S",duration:"Concentration, up to 1 hour",classes:["Cleric","Druid","Ranger","Sorcerer","Wizard","Paladin"],description:"For the duration, the willing creature you touch has resistance to one damage type of your choice: acid, cold, fire, lightning, or thunder."},
{name:"Revivify",level:3,school:"Necromancy",castingTime:"1 action",range:"Touch",components:"V, S, M (diamonds worth 300 gp, which the spell consumes)",duration:"Instantaneous",classes:["Cleric","Druid","Paladin"],description:"You touch a creature that has died within the last minute. That creature returns to life with 1 hit point. This spell can't return to life a creature that has died of old age, nor can it restore any missing body parts."},
{name:"Sending",level:3,school:"Evocation",castingTime:"1 action",range:"Unlimited",components:"V, S, M (a short piece of fine copper wire)",duration:"1 round",classes:["Bard","Cleric","Wizard"],description:"You send a short message of twenty-five words or less to a creature with which you are familiar. The creature hears the message in its mind, recognizes you as the sender if it knows you, and can answer in a like manner immediately."},
{name:"Slow",level:3,school:"Transmutation",castingTime:"1 action",range:"120 feet",components:"V, S, M (a drop of molasses)",duration:"Concentration, up to 1 minute",classes:["Sorcerer","Wizard"],description:"You alter time around up to six creatures of your choice in a 40-foot cube within range. Each target must succeed on a Wisdom saving throw or be affected by this spell for the duration. An affected target's speed is halved, it takes a −2 penalty to AC and Dexterity saving throws, and it can't use reactions."},
{name:"Vampiric Touch",level:3,school:"Necromancy",castingTime:"1 action",range:"Self",components:"V, S",duration:"Concentration, up to 1 minute",classes:["Warlock","Wizard"],description:"The touch of your shadow-wreathed hand can siphon life force from others to heal your wounds. Make a melee spell attack against a creature within your reach. On a hit, the target takes 3d6 necrotic damage, and you regain hit points equal to half the amount of necrotic damage dealt. Until the spell ends, you can make the attack again on each of your turns as an action.",damage:"3d6 necrotic"},

// LEVEL 4
{name:"Banishment",level:4,school:"Abjuration",castingTime:"1 action",range:"60 feet",components:"V, S, M (an item distasteful to the target)",duration:"Concentration, up to 1 minute",classes:["Cleric","Paladin","Sorcerer","Warlock","Wizard"],description:"You attempt to send one creature that you can see within range to another plane of existence. The target must succeed on a Charisma saving throw or be banished. If the target is native to the plane of existence you're on, you banish the target to a harmless demiplane."},
{name:"Blight",level:4,school:"Necromancy",castingTime:"1 action",range:"30 feet",components:"V, S",duration:"Instantaneous",classes:["Druid","Sorcerer","Warlock","Wizard"],description:"Necromantic energy washes over a creature of your choice that you can see within range, draining moisture and vitality from it. The target must make a Constitution saving throw. The target takes 8d8 necrotic damage on a failed save, or half as much damage on a successful one. This spell has no effect on undead or constructs. At Higher Levels: When you cast this spell using a spell slot of 5th level or higher, the damage increases by 1d8 for each slot level above 4th.",damage:"8d8 necrotic"},
{name:"Confusion",level:4,school:"Enchantment",castingTime:"1 action",range:"90 feet",components:"V, S, M (three nut shells)",duration:"Concentration, up to 1 minute",classes:["Bard","Druid","Sorcerer","Wizard"],description:"This spell assaults and twists creatures' minds, spawning delusions and provoking uncontrolled action. Each creature in a 10-foot-radius sphere centered on a point you choose within range must succeed on a Wisdom saving throw when you cast this spell or be affected by it."},
{name:"Dimension Door",level:4,school:"Conjuration",castingTime:"1 action",range:"500 feet",components:"V",duration:"Instantaneous",classes:["Bard","Sorcerer","Warlock","Wizard","Paladin"],description:"You teleport yourself from your current location to any other spot within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction, such as '200 feet straight downward' or 'upward to the northwest at a 45-degree angle, 300 feet.'"},
{name:"Evard's Black Tentacles",level:4,school:"Conjuration",castingTime:"1 action",range:"90 feet",components:"V, S, M (a piece of tentacle from a giant octopus or a giant squid)",duration:"Concentration, up to 1 minute",classes:["Wizard"],description:"Squirming, ebony tentacles fill a 20-foot square on ground that you can see within range. For the duration, these tentacles turn the ground in the area into difficult terrain. When a creature enters the affected area for the first time on a turn or starts its turn there, the creature must succeed on a Dexterity saving throw or take 3d6 bludgeoning damage and be restrained by the tentacles until the spell ends.",damage:"3d6 bludgeoning"},
{name:"Freedom of Movement",level:4,school:"Abjuration",castingTime:"1 action",range:"Touch",components:"V, S, M (a leather strap, bound around the arm or a similar appendage)",duration:"1 hour",classes:["Bard","Cleric","Druid","Ranger"],description:"You touch a willing creature. For the duration, the target's movement is unaffected by difficult terrain, and spells and other magical effects can neither reduce the target's speed nor cause the target to be paralyzed or restrained. The target can also spend 5 feet of movement to automatically escape from nonmagical restraints, such as manacles or a creature that has it grappled."},
{name:"Greater Invisibility",level:4,school:"Illusion",castingTime:"1 action",range:"Touch",components:"V, S",duration:"Concentration, up to 1 minute",classes:["Bard","Sorcerer","Wizard"],description:"You or a creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target's person."},
{name:"Hallucinatory Terrain",level:4,school:"Illusion",castingTime:"10 minutes",range:"300 feet",components:"V, S, M (a stone, a twig, and a bit of green plant)",duration:"24 hours",classes:["Bard","Druid","Warlock","Wizard"],description:"You make natural terrain in a 150-foot cube in range look, sound, and smell like some other sort of natural terrain. Thus, open fields or a road can be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain."},
{name:"Ice Storm",level:4,school:"Evocation",castingTime:"1 action",range:"300 feet",components:"V, S, M (a pinch of dust and a few drops of water)",duration:"Instantaneous",classes:["Druid","Sorcerer","Wizard"],description:"A hail of rock-hard ice pounds to the ground in a 20-foot-radius, 40-foot-high cylinder centered on a point within range. Each creature in the cylinder must make a Dexterity saving throw. A creature takes 2d8 bludgeoning damage and 4d6 cold damage on a failed save, or half as much damage on a successful one. At Higher Levels: When you cast this spell using a spell slot of 5th level or higher, the bludgeoning damage increases by 1d8 for each slot level above 4th.",damage:"2d8 bludgeoning + 4d6 cold"},
{name:"Phantasmal Killer",level:4,school:"Illusion",castingTime:"1 action",range:"120 feet",components:"V, S",duration:"Concentration, up to 1 minute",classes:["Wizard","Warlock"],description:"You tap into the nightmares of a creature you can see within range and create an illusory manifestation of its deepest fears, visible only to that creature. The target must make a Wisdom saving throw. On a failed save, the target becomes frightened for the duration. At the end of each of the target's turns before the spell ends, the target must succeed on a Wisdom saving throw or take 4d10 psychic damage. On a successful save, the spell ends.",damage:"4d10 psychic"},
{name:"Polymorph",level:4,school:"Transmutation",castingTime:"1 action",range:"60 feet",components:"V, S, M (a caterpillar cocoon)",duration:"Concentration, up to 1 hour",classes:["Bard","Druid","Sorcerer","Wizard"],description:"This spell transforms a creature that you can see within range into a new form. An unwilling creature must make a Wisdom saving throw to avoid the effect. The spell has no effect on a shapechanger or a creature with 0 hit points. The transformation lasts for the duration, or until the target drops to 0 hit points or dies."},
{name:"Staggering Smite",level:4,school:"Evocation",castingTime:"1 bonus action",range:"Self",components:"V",duration:"Concentration, up to 1 minute",classes:["Paladin","Warlock"],description:"The next time you hit a creature with a melee weapon attack during this spell's duration, your weapon pierces both body and mind, and the attack deals an extra 4d6 psychic damage to the target. The target must make a Wisdom saving throw. On a failed save, it has disadvantage on attack rolls and ability checks, and can't take reactions, until the end of its next turn.",damage:"4d6 psychic"},
{name:"Stone Shape",level:4,school:"Transmutation",castingTime:"1 action",range:"Touch",components:"V, S, M (soft clay, which must be worked into roughly the desired shape of the stone object)",duration:"Instantaneous",classes:["Cleric","Druid","Wizard"],description:"You touch a stone object of Medium size or smaller or a section of stone no more than 5 feet in any dimension and form it into any shape that suits your purpose."},
{name:"Wall of Fire",level:4,school:"Evocation",castingTime:"1 action",range:"120 feet",components:"V, S, M (a small piece of phosphorus)",duration:"Concentration, up to 1 minute",classes:["Druid","Sorcerer","Wizard"],description:"You create a wall of fire on a solid surface within range. The wall can be up to 60 feet long, 20 feet high, and 1 foot thick, or a ringed wall up to 20 feet in diameter, 20 feet high, and 1 foot thick. The wall is opaque and lasts for the duration. When the wall appears, each creature within its area must make a Dexterity saving throw. On a failed save, a creature takes 5d8 fire damage, or half as much damage on a successful save.",damage:"5d8 fire"},

// LEVEL 5
{name:"Banishing Smite",level:5,school:"Abjuration",castingTime:"1 bonus action",range:"Self",components:"V",duration:"Concentration, up to 1 minute",classes:["Paladin","Warlock"],description:"The next time you hit a creature with a weapon attack before this spell ends, your weapon crackles with force, and the attack deals an extra 5d10 force damage to the target. Additionally, if this attack reduces the target to 50 hit points or fewer, you banish it. If the target is native to a different plane of existence than the one you're on, the target disappears, returning to its home plane.",damage:"5d10 force"},
{name:"Cone of Cold",level:5,school:"Evocation",castingTime:"1 action",range:"Self (60-foot cone)",components:"V, S, M (a small crystal or glass cone)",duration:"Instantaneous",classes:["Sorcerer","Wizard","Warlock"],description:"A blast of cold air erupts from your hands. Each creature in a 60-foot cone must make a Constitution saving throw. A creature takes 8d8 cold damage on a failed save, or half as much damage on a successful one. A creature killed by this spell becomes a frozen statue until it thaws. At Higher Levels: When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.",damage:"8d8 cold"},
{name:"Dream",level:5,school:"Illusion",castingTime:"1 minute",range:"Special",components:"V, S, M (a handful of sand, a dab of ink, and a writing quill plucked from a sleeping bird)",duration:"8 hours",classes:["Bard","Warlock","Wizard"],description:"This spell shapes a creature's dreams. Choose a creature known to you as the target of this spell. The target must be asleep. You, or a willing creature you touch, enters a trance state, acting as a messenger. While in the trance, the messenger is aware of his or her surroundings, but can't take actions or move."},
{name:"Dominate Person",level:5,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Concentration, up to 1 minute",classes:["Bard","Sorcerer","Wizard"],description:"You attempt to beguile a humanoid that you can see within range. It must succeed on a Wisdom saving throw or be charmed by you for the duration. While the target is charmed, you have a telepathic link with it as long as the two of you are on the same plane of existence."},
{name:"Hold Monster",level:5,school:"Enchantment",castingTime:"1 action",range:"90 feet",components:"V, S, M (a small, straight piece of iron)",duration:"Concentration, up to 1 minute",classes:["Bard","Sorcerer","Warlock","Wizard","Paladin"],description:"Choose a creature that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. This spell has no effect on undead. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target."},
{name:"Mass Cure Wounds",level:5,school:"Evocation",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Instantaneous",classes:["Bard","Cleric","Druid"],description:"A wave of healing energy washes out from a point of your choice within range. Choose up to six creatures in a 30-foot-radius sphere centered on that point. Each target regains hit points equal to 3d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs. At Higher Levels: When you cast this spell using a spell slot of 6th level or higher, the healing increases by 1d8 for each slot level above 5th.",damage:"3d8+mod healing"},
{name:"Mislead",level:5,school:"Illusion",castingTime:"1 action",range:"Self",components:"S",duration:"Concentration, up to 1 hour",classes:["Bard","Warlock","Wizard"],description:"You become invisible at the same time that an illusory double of you appears where you are standing. The double lasts for the duration, but the invisibility ends if you attack or cast a spell."},
{name:"Scrying",level:5,school:"Divination",castingTime:"10 minutes",range:"Self",components:"V, S, M (a focus worth at least 1,000 gp, such as a crystal ball, a silver mirror, or a font filled with holy water)",duration:"Concentration, up to 10 minutes",classes:["Bard","Cleric","Druid","Warlock","Wizard","Paladin"],description:"You can see and hear a particular creature you choose that is on the same plane of existence as you. The target must make a Wisdom saving throw, which is modified by how well you know the target and the sort of physical connection you have to it."},
{name:"Seeming",level:5,school:"Illusion",castingTime:"1 action",range:"30 feet",components:"V, S",duration:"8 hours",classes:["Bard","Sorcerer","Wizard"],description:"This spell allows you to change the appearance of any number of creatures that you can see within range. You give each target you choose a new, illusory appearance. An unwilling target can make a Charisma saving throw, and if it succeeds, it is unaffected by this spell."},
{name:"Telekinesis",level:5,school:"Transmutation",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Concentration, up to 10 minutes",classes:["Sorcerer","Wizard"],description:"You gain the ability to move or manipulate creatures or objects by thought. When you cast the spell, and as your action each round for the duration, you can exert your will on one creature or object that you can see within range, causing the appropriate effect below."},

// LEVEL 6
{name:"Chain Lightning",level:6,school:"Evocation",castingTime:"1 action",range:"150 feet",components:"V, S, M (a bit of fur; a piece of amber, glass, or a crystal rod; and three silver pins)",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"You create a bolt of lightning that arcs toward a target of your choice that you can see within range. Three bolts then leap from that target to as many as three other targets, each of which must be within 30 feet of the first target. A target can be a creature or an object and can be targeted by only one of the bolts. A target must make a Dexterity saving throw. The target takes 10d8 lightning damage on a failed save, or half as much damage on a successful one.",damage:"10d8 lightning"},
{name:"Disintegrate",level:6,school:"Transmutation",castingTime:"1 action",range:"60 feet",components:"V, S, M (a lodestone and a pinch of dust)",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"A thin green ray springs from your pointing finger to a target that you can see within range. The target can be a creature, an object, or a creation of magical force, such as the wall created by wall of force. A creature targeted by this spell must make a Dexterity saving throw. On a failed save, the target takes 10d6 + 40 force damage. The target is disintegrated if this damage leaves it with 0 hit points.",damage:"10d6+40 force"},
{name:"Eyebite",level:6,school:"Necromancy",castingTime:"1 action",range:"Self",components:"V, S",duration:"Concentration, up to 1 minute",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"For the spell's duration, your eyes become an inky void imbued with dread power. One creature of your choice within 60 feet of you that you can see must succeed on a Wisdom saving throw or be affected by one of the following effects of your choice for the duration: Asleep, Panicked, or Sickened."},
{name:"Globe of Invulnerability",level:6,school:"Abjuration",castingTime:"1 action",range:"Self (10-foot radius)",components:"V, S, M (a glass or crystal bead that shatters when the spell ends)",duration:"Concentration, up to 1 minute",classes:["Sorcerer","Wizard"],description:"An immobile, faintly shimmering barrier springs into existence in a 10-foot radius around you and remains for the duration. Any spell of 5th level or lower cast from outside the barrier can't affect creatures or objects within it, even if the spell is cast using a higher level spell slot."},
{name:"Mass Suggestion",level:6,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V, M (a snake's tongue and either a bit of honeycomb or a drop of sweet oil)",duration:"24 hours",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"You suggest a course of activity (limited to a sentence or two) and magically influence up to twelve creatures of your choice that you can see within range and that can hear and understand you. At Higher Levels: When you cast this spell using a 7th-level spell slot, the duration is 10 days. When you use an 8th-level spell slot, the duration is 30 days. When you use a 9th-level spell slot, the duration is a year and a day."},
{name:"Sunbeam",level:6,school:"Evocation",castingTime:"1 action",range:"Self (60-foot line)",components:"V, S, M (a magnifying glass)",duration:"Concentration, up to 1 minute",classes:["Druid","Sorcerer","Wizard"],description:"A beam of brilliant light flashes out from your hand in a 5-foot-wide, 60-foot-line. Each creature in the line must make a Constitution saving throw. On a failed save, a creature takes 6d8 radiant damage and is blinded until your next turn. On a successful save, it takes half as much damage and isn't blinded by this spell.",damage:"6d8 radiant"},
{name:"True Seeing",level:6,school:"Divination",castingTime:"1 action",range:"Touch",components:"V, S, M (an ointment for the eyes that costs 25 gp, is made from mushroom powder, saffron, and fat, and is consumed by the spell)",duration:"1 hour",classes:["Bard","Cleric","Sorcerer","Warlock","Wizard"],description:"You give the willing creature you touch the ability to see things as they actually are. For the duration, the creature has truesight, notices secret doors hidden by magic, and can see into the Ethereal Plane, all out to a range of 120 feet."},

// LEVEL 7
{name:"Finger of Death",level:7,school:"Necromancy",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Instantaneous",classes:["Sorcerer","Warlock","Wizard"],description:"You send negative energy coursing through a creature that you can see within range, causing it searing pain. The target must make a Constitution saving throw. It takes 7d8 + 30 necrotic damage on a failed save, or half as much damage on a successful save. A humanoid killed by this spell rises at the start of your next turn as a zombie that is permanently under your command.",damage:"7d8+30 necrotic"},
{name:"Forcecage",level:7,school:"Evocation",castingTime:"1 action",range:"100 feet",components:"V, S, M (ruby dust worth 1,500 gp)",duration:"1 hour",classes:["Bard","Warlock","Wizard"],description:"An immobile, invisible, cube-shaped prison composed of magical force springs into existence around an area you choose within range. The prison can be a cage or a solid box, as you choose."},
{name:"Plane Shift",level:7,school:"Conjuration",castingTime:"1 action",range:"Touch",components:"V, S, M (a forked, metal rod worth at least 250 gp, attuned to a specific plane of existence)",duration:"Instantaneous",classes:["Cleric","Druid","Sorcerer","Warlock","Wizard"],description:"You and up to eight willing creatures who link hands in a circle are transported to a different plane of existence. You can specify a target destination in general terms, such as the City of Brass on the Elemental Plane of Fire or the palace of Dispater on the second level of the Nine Hells, and you appear in or near that destination."},
{name:"Power Word Pain",level:7,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V",duration:"Instantaneous",classes:["Sorcerer","Warlock","Wizard"],description:"You speak a word of power that causes waves of intense pain to assail one creature you can see within range. If the target has 100 hit points or fewer, it is subject to crippling pain. Otherwise, the spell has no effect on it. A target is also unaffected if it is immune to being charmed."},
{name:"Teleport",level:7,school:"Conjuration",castingTime:"1 action",range:"10 feet",components:"V",duration:"Instantaneous",classes:["Bard","Sorcerer","Wizard"],description:"This spell instantly transports you and up to eight willing creatures of your choice that you can see within range, or a single object that you can see within range, to a destination you select."},

// LEVEL 8
{name:"Abi-Dalzim's Horrid Wilting",level:8,school:"Necromancy",castingTime:"1 action",range:"150 feet",components:"V, S, M (a bit of sponge)",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"You draw the moisture from every creature in a 30-foot cube centered on a point you choose within range. Each creature in that area must make a Constitution saving throw. Constructs and undead aren't affected, and plants and water elementals make this saving throw with disadvantage. A creature takes 12d8 necrotic damage on a failed save, or half as much damage on a successful one.",damage:"12d8 necrotic"},
{name:"Dominate Monster",level:8,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V, S",duration:"Concentration, up to 1 hour",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"You attempt to beguile a creature that you can see within range. It must succeed on a Wisdom saving throw or be charmed by you for the duration. While the creature is charmed, you have a telepathic link with it as long as the two of you are on the same plane of existence."},
{name:"Feeblemind",level:8,school:"Enchantment",castingTime:"1 action",range:"150 feet",components:"V, S, M (a handful of clay, crystal, glass, or mineral spheres)",duration:"Instantaneous",classes:["Bard","Druid","Warlock","Wizard"],description:"You blast the mind of a creature that you can see within range, attempting to shatter its intellect and personality. The target takes 4d6 psychic damage and must make an Intelligence saving throw. On a failed save, the creature's Intelligence and Charisma scores become 1. The creature can't cast spells, activate magic items, understand language, or communicate in any intelligible way.",damage:"4d6 psychic"},
{name:"Glibness",level:8,school:"Transmutation",castingTime:"1 action",range:"Self",components:"V",duration:"1 hour",classes:["Bard","Warlock"],description:"Until the spell ends, when you make a Charisma check, you can replace the number you roll with a 15. Additionally, no matter what you say, magic that would determine if you are telling the truth indicates that you are being truthful."},
{name:"Power Word Stun",level:8,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V",duration:"Instantaneous",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"You speak a word of power that overwhelms the mind of one creature you can see within range, leaving it dumbfounded. If the target has 150 hit points or fewer, it is stunned. Otherwise, the spell has no effect. The stunned target must make a Constitution saving throw at the end of each of its turns. On a successful save, this stunning effect ends."},

// LEVEL 9
{name:"Foresight",level:9,school:"Divination",castingTime:"1 minute",range:"Touch",components:"V, S, M (a hummingbird feather)",duration:"8 hours",classes:["Bard","Druid","Warlock","Wizard"],description:"You touch a willing creature and bestow a limited ability to see into the immediate future. For the duration, the target can't be surprised and has advantage on attack rolls, ability checks, and saving throws. Additionally, other creatures have disadvantage on attack rolls against the target for the duration."},
{name:"Meteor Swarm",level:9,school:"Evocation",castingTime:"1 action",range:"1 mile",components:"V, S",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"Blazing orbs of fire plummet to the ground at four different points you can see within range. Each creature in a 40-foot-radius sphere centered on each point you choose must make a Dexterity saving throw. The sphere spreads around corners. A creature takes 20d6 fire damage and 20d6 bludgeoning damage on a failed save, or half as much damage on a successful one.",damage:"20d6 fire + 20d6 bludgeoning"},
{name:"Power Word Kill",level:9,school:"Enchantment",castingTime:"1 action",range:"60 feet",components:"V",duration:"Instantaneous",classes:["Bard","Sorcerer","Warlock","Wizard"],description:"You utter a word of power that can compel one creature you can see within range to die instantly. If the creature you choose has 100 hit points or fewer, it dies. Otherwise, the spell has no effect."},
{name:"Time Stop",level:9,school:"Transmutation",castingTime:"1 action",range:"Self",components:"V",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"You briefly stop the flow of time for everyone but yourself. No time passes for other creatures, while you take 1d4 + 1 turns in a row, during which you can use actions and move as normal. This effect ends if one of the actions you use during this period, or any effects that you create during this period, affects a creature other than you or an object being worn or carried by someone other than you."},
{name:"True Polymorph",level:9,school:"Transmutation",castingTime:"1 action",range:"30 feet",components:"V, S, M (a drop of mercury, a dollop of gum arabic, and a wisp of smoke)",duration:"Concentration, up to 1 hour",classes:["Bard","Warlock","Wizard"],description:"Choose one creature or nonmagical object that you can see within range. You transform the creature into a different creature, the creature into an object, or the object into a creature. The transformation lasts for the duration, or until the target drops to 0 hit points or dies. If you concentrate on this spell for the full duration, the transformation lasts until it is dispelled."},
{name:"Wish",level:9,school:"Conjuration",castingTime:"1 action",range:"Self",components:"V",duration:"Instantaneous",classes:["Sorcerer","Wizard"],description:"Wish is the mightiest spell a mortal creature can cast. By simply speaking aloud, you can alter the very foundations of reality in accord with your desires. The basic use of this spell is to duplicate any other spell of 8th level or lower. You don't need to meet any requirements in that spell, including costly components. The spell simply takes effect."}
];
